import{_ as e,o as r,c as o,a3 as t}from"./chunks/framework.DACwFHq9.js";const c=JSON.parse('{"title":"🎨 媒体生成中心：资产管理","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/media-generator/asset-management.md","filePath":"user-guide/tools/media-generator/asset-management.md","lastUpdated":1778221347000}'),l={name:"user-guide/tools/media-generator/asset-management.md"};function i(n,a,s,d,h,g){return r(),o("div",null,[...a[0]||(a[0]=[t('<h1 id="🎨-媒体生成中心-资产管理" tabindex="-1">🎨 媒体生成中心：资产管理 <a class="header-anchor" href="#🎨-媒体生成中心-资产管理" aria-label="Permalink to &quot;🎨 媒体生成中心：资产管理&quot;">​</a></h1><blockquote><p>了解生成结果的保存、查看和管理方式，以及与系统资产管理器的深度集成。<br><strong>TODO：截图</strong></p></blockquote><hr><h2 id="生成结果的自动入库" tabindex="-1">生成结果的自动入库 <a class="header-anchor" href="#生成结果的自动入库" aria-label="Permalink to &quot;生成结果的自动入库&quot;">​</a></h2><p><strong>媒体生成中心</strong>与系统的 <strong>资产管理器</strong>（Asset Manager）深度集成。每次媒体生成任务成功完成后，结果会自动：</p><ol><li><strong>导入资产系统</strong> —— 生成的文件（图片/视频/音频）自动注册为系统资产，保存在统一存储目录下</li><li><strong>嵌入元数据</strong> —— 提示词、模型名称、参数快照、种子值等生成信息被直接嵌入到文件元数据中（支持 PNG/JPEG/WebP/MP4 等格式）</li><li><strong>持久化衍生数据</strong> —— 额外的生成信息（如修订后的提示词 <code>revisedPrompt</code>）作为一个独立的 JSON 文件存放，关联到资产</li></ol><p>这意味着你<strong>不需要手动保存</strong>生成结果——它们已经被系统妥善管理。</p><hr><h2 id="在工作台中查看" tabindex="-1">在工作台中查看 <a class="header-anchor" href="#在工作台中查看" aria-label="Permalink to &quot;在工作台中查看&quot;">​</a></h2><h3 id="右侧面板-生成历史" tabindex="-1">右侧面板：生成历史 <a class="header-anchor" href="#右侧面板-生成历史" aria-label="Permalink to &quot;右侧面板：生成历史&quot;">​</a></h3><p>工作台右侧的 <strong>生成历史</strong> 面板展示了当前会话相关的生成结果：</p><ul><li>按类型筛选（全部 / 图片 / 视频 / 音频）</li><li>点击缩略图即可预览（图片使用 ImageViewer，视频和音频分别使用对应的播放器）</li><li>点击刷新按钮手动更新列表</li></ul><h3 id="画廊标签页" tabindex="-1">画廊标签页 <a class="header-anchor" href="#画廊标签页" aria-label="Permalink to &quot;画廊标签页&quot;">​</a></h3><p>切换到 <strong>「画廊」</strong> 标签页，可以浏览<strong>所有</strong>通过媒体生成中心产出的结果：</p><ul><li><strong>搜索</strong>：按提示词或模型名称搜索（支持后端搜索和前端分页两种方式）</li><li><strong>筛选</strong>：按媒体类型（图片/视频/音频）快速过滤</li><li><strong>卡片预览</strong>：鼠标悬停时显示提示词摘要，图片直接显示缩略图，视频支持 hover 播放</li><li><strong>操作按钮</strong>（鼠标悬停浮现）： <ul><li>📋 <strong>查看参数</strong> —— 查看该资产对应的生成参数详情</li><li>⬇️ <strong>下载</strong> —— 下载原始文件到本地</li><li>🗑️ <strong>删除</strong> —— 将资产从媒体生成中心的来源列表中移除。<strong>注意</strong>：这仅解除资产与本工具的关联，不会物理删除资产文件，你仍可以在资产管理器中找到它。</li></ul></li></ul><blockquote><p>画廊采用<strong>无限滚动</strong>加载，滚动到底部自动加载更多结果。</p></blockquote><hr><h2 id="跨工具集成-在资产管理器中查看" tabindex="-1">跨工具集成：在资产管理器中查看 <a class="header-anchor" href="#跨工具集成-在资产管理器中查看" aria-label="Permalink to &quot;跨工具集成：在资产管理器中查看&quot;">​</a></h2><p>媒体生成中心在系统资产管理器中注册了两个便捷功能，你可以在任何工具的资产上下文中使用：</p><ol><li><p><strong>查看生成参数</strong> —— 当你在资产管理器中选中一个由媒体生成中心产出的文件时，右键菜单中会出现「查看生成参数」选项。点击后会弹出参数详情对话框，显示：</p><ul><li>提示词（Prompt）</li><li>负向提示词（Negative Prompt）</li><li>使用的模型（Model ID）</li><li>核心参数快照（Size, Seed, Steps, CFG Scale 等）</li><li>修正后的提示词（Revised Prompt，如果模型自动优化了你的输入）</li></ul></li><li><p><strong>元数据降级读取</strong> —— 如果资产文件中没有内嵌元数据，系统会尝试从文件中的元数据系统提取；如果仍不存在，会提示「未找到生成参数信息」。</p></li></ol><hr><h2 id="会话持久化" tabindex="-1">会话持久化 <a class="header-anchor" href="#会话持久化" aria-label="Permalink to &quot;会话持久化&quot;">​</a></h2><p>除了资产，<strong>会话记录</strong>（包括提示词、分支树、参数配置等上下文）也被自动持久化到本地文件系统：</p><ul><li><strong>存储位置</strong>：<code>appDataDir / media-generator / sessions /</code></li><li><strong>索引文件</strong>：<code>sessions-index.json</code> 维护所有会话的轻量级索引（ID、名称、时间戳、任务数）</li><li><strong>会话文件</strong>：每个会话一个独立的 JSON 文件，包含完整的节点树和状态</li></ul><p>这意味着：</p><ul><li>关闭应用后重新打开，所有会话历史和生成记录完好无损</li><li>支持创建多个会话并在它们之间切换</li><li>每个会话可独立修改名称方便管理</li></ul><hr><h2 id="批量管理操作" tabindex="-1">批量管理操作 <a class="header-anchor" href="#批量管理操作" aria-label="Permalink to &quot;批量管理操作&quot;">​</a></h2><h3 id="会话模式下" tabindex="-1">会话模式下 <a class="header-anchor" href="#会话模式下" aria-label="Permalink to &quot;会话模式下&quot;">​</a></h3><p>在创作会话中，点击头部工具栏的「批量操作」按钮进入批量模式：</p><ul><li><strong>批量选中</strong>：勾选多条消息记录</li><li><strong>批量下载</strong>：选中多条结果的下载（功能开发中，敬请期待）</li><li><strong>批量删除</strong>：确认后删除选中的消息及其关联任务</li></ul><h3 id="任务列表模式下" tabindex="-1">任务列表模式下 <a class="header-anchor" href="#任务列表模式下" aria-label="Permalink to &quot;任务列表模式下&quot;">​</a></h3><p>在「任务列表」标签页，你可以：</p><ul><li><strong>清空已结束任务</strong>：一键移除所有已完成/失败/已取消的任务</li><li><strong>单个操作</strong>：每个任务卡片支持复制提示词、取消生成、重新生成、下载结果、删除</li></ul><hr><h2 id="常见场景" tabindex="-1">常见场景 <a class="header-anchor" href="#常见场景" aria-label="Permalink to &quot;常见场景&quot;">​</a></h2><h3 id="q-生成的结果保存在哪里" tabindex="-1">Q：生成的结果保存在哪里？ <a class="header-anchor" href="#q-生成的结果保存在哪里" aria-label="Permalink to &quot;Q：生成的结果保存在哪里？&quot;">​</a></h3><p>文件存储在系统的资产目录中（<code>appDataDir / assets /</code>），通过资产管理器统一管理。会话元数据则存储在 <code>appDataDir / media-generator /</code>。</p><h3 id="q-如何找回之前生成的作品" tabindex="-1">Q：如何找回之前生成的作品？ <a class="header-anchor" href="#q-如何找回之前生成的作品" aria-label="Permalink to &quot;Q：如何找回之前生成的作品？&quot;">​</a></h3><p>三种方式：</p><ol><li>在画廊中按时间倒序浏览所有结果</li><li>通过会话管理器切换到历史会话，查看当时的生成流</li><li>在资产管理器中按来源模块 <code>media-generator</code> 筛选</li></ol><h3 id="q-删除任务会影响资产文件吗" tabindex="-1">Q：删除任务会影响资产文件吗？ <a class="header-anchor" href="#q-删除任务会影响资产文件吗" aria-label="Permalink to &quot;Q：删除任务会影响资产文件吗？&quot;">​</a></h3><p><strong>不会</strong>。删除任务只会从任务列表中移除该记录，已经导入到资产系统的文件不会被删除。要清理资产，请使用资产管理器。</p><h3 id="q-可以批量导出生成参数吗" tabindex="-1">Q：可以批量导出生成参数吗？ <a class="header-anchor" href="#q-可以批量导出生成参数吗" aria-label="Permalink to &quot;Q：可以批量导出生成参数吗？&quot;">​</a></h3><p>当前支持按分支导出 Markdown 或 JSON 格式的生成记录（包含提示词、参数快照和结果列表）。可以在会话的对话框中触发导出操作。</p>',45)])])}const p=e(l,[["render",i]]);export{c as __pageData,p as default};
